PRAGMA foreign_keys = OFF;
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:14', 83, 14, 30, 588, 5862, 'كَلَّا بَلْ ۜرَانَ عَلٰى قُلُوْبِهِمْ مَّا كَانُوْا يَكْسِبُوْنَ ', 'Sekali-kali tidak! Bahkan, apa yang selalu mereka kerjakan itu telah menutupi hati mereka. ', '', 'https://everyayah.com/data/Alafasy_128kbps/083014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:15', 83, 15, 30, 588, 5863, 'كَلَّآ اِنَّهُمْ عَنْ رَّبِّهِمْ يَوْمَىِٕذٍ لَّمَحْجُوْبُوْنَۗ', 'Sekali-kali tidak!749) Sesungguhnya mereka pada hari itu benar-benar terhalang dari (rahmat) Tuhannya. ', '749) Maksudnya adalah sekali-kali tidak seperti apa yang mereka katakan, yakni bahwa mereka dekat pada sisi Tuhan.', 'https://everyayah.com/data/Alafasy_128kbps/083015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:16', 83, 16, 30, 588, 5864, 'ثُمَّ اِنَّهُمْ لَصَالُوا الْجَحِيْمِۗ', 'Sesungguhnya mereka kemudian benar-benar masuk (neraka) Jahim. ', '', 'https://everyayah.com/data/Alafasy_128kbps/083016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:17', 83, 17, 30, 588, 5865, 'ثُمَّ يُقَالُ هٰذَا الَّذِيْ كُنْتُمْ بِهٖ تُكَذِّبُوْنَۗ', 'Lalu dikatakan (kepada mereka), “Inilah (azab) yang selalu kamu dustakan.”', '', 'https://everyayah.com/data/Alafasy_128kbps/083017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:18', 83, 18, 30, 588, 5866, 'كَلَّآ اِنَّ كِتٰبَ الْاَبْرَارِ لَفِيْ عِلِّيِّيْنَۗ ', 'Sekali-kali tidak! Sesungguhnya catatan orang-orang yang berbakti benar-benar tersimpan dalam ‘Illiyyīn.750)', '750) ‘Illiyyīn adalah nama kitab yang mencatat segala perbuatan orang-orang yang beramal saleh.', 'https://everyayah.com/data/Alafasy_128kbps/083018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:19', 83, 19, 30, 588, 5867, 'وَمَآ اَدْرٰىكَ مَا عِلِّيُّوْنَۗ', 'Tahukah engkau apakah ‘Illiyyīn itu?', '', 'https://everyayah.com/data/Alafasy_128kbps/083019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:20', 83, 20, 30, 588, 5868, 'كِتٰبٌ مَّرْقُوْمٌۙ', '(Itulah) kitab yang berisi catatan (amal)', '', 'https://everyayah.com/data/Alafasy_128kbps/083020.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:21', 83, 21, 30, 588, 5869, 'يَّشْهَدُهُ الْمُقَرَّبُوْنَۗ', 'yang disaksikan oleh (malaikat-malaikat) yang didekatkan (kepada Allah). ', '', 'https://everyayah.com/data/Alafasy_128kbps/083021.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:22', 83, 22, 30, 588, 5870, 'اِنَّ الْاَبْرَارَ لَفِيْ نَعِيْمٍۙ', 'Sesungguhnya orang-orang yang berbakti benar-benar berada dalam (surga yang penuh) kenikmatan.', '', 'https://everyayah.com/data/Alafasy_128kbps/083022.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:23', 83, 23, 30, 588, 5871, 'عَلَى الْاَرَاۤىِٕكِ يَنْظُرُوْنَۙ', 'Mereka (duduk) di atas dipan-dipan (sambil) melepas pandangan. ', '', 'https://everyayah.com/data/Alafasy_128kbps/083023.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:24', 83, 24, 30, 588, 5872, 'تَعْرِفُ فِيْ وُجُوْهِهِمْ نَضْرَةَ النَّعِيْمِۚ', 'Engkau dapat mengetahui pada wajah mereka gemerlapnya kenikmatan.', '', 'https://everyayah.com/data/Alafasy_128kbps/083024.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:25', 83, 25, 30, 588, 5873, 'يُسْقَوْنَ مِنْ رَّحِيْقٍ مَّخْتُوْمٍۙ', 'Mereka diberi minum dari khamar murni (tidak memabukkan) yang (tempatnya) masih diberi lak (sebagai jaminan keasliannya).', '', 'https://everyayah.com/data/Alafasy_128kbps/083025.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:26', 83, 26, 30, 588, 5874, 'خِتٰمُهٗ مِسْكٌ ۗوَفِيْ ذٰلِكَ فَلْيَتَنَافَسِ الْمُتَنٰفِسُوْنَۗ', 'Laknya terbuat dari kasturi. Untuk (mendapatkan) yang demikian itu hendaknya orang berlomba-lomba. ', '', 'https://everyayah.com/data/Alafasy_128kbps/083026.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:27', 83, 27, 30, 588, 5875, 'وَمِزَاجُهٗ مِنْ تَسْنِيْمٍۙ', 'Campurannya terbuat dari tasnīm,', '', 'https://everyayah.com/data/Alafasy_128kbps/083027.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:28', 83, 28, 30, 588, 5876, 'عَيْنًا يَّشْرَبُ بِهَا الْمُقَرَّبُوْنَۗ', '(yaitu) mata air yang diminum oleh mereka yang didekatkan (kepada Allah). ', '', 'https://everyayah.com/data/Alafasy_128kbps/083028.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:29', 83, 29, 30, 588, 5877, 'اِنَّ الَّذِيْنَ اَجْرَمُوْا كَانُوْا مِنَ الَّذِيْنَ اٰمَنُوْا يَضْحَكُوْنَۖ', 'Sesungguhnya orang-orang yang berdosa adalah mereka yang dahulu selalu mentertawakan orang-orang yang beriman.', '', 'https://everyayah.com/data/Alafasy_128kbps/083029.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:30', 83, 30, 30, 588, 5878, 'وَاِذَا مَرُّوْا بِهِمْ يَتَغَامَزُوْنَۖ', 'Apabila mereka (orang-orang yang beriman) melintas di hadapan mereka, mereka saling mengedip-ngedipkan matanya.', '', 'https://everyayah.com/data/Alafasy_128kbps/083030.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:31', 83, 31, 30, 588, 5879, 'وَاِذَا انْقَلَبُوْٓا اِلٰٓى اَهْلِهِمُ انْقَلَبُوْا فَكِهِيْنَۖ', 'Apabila kembali kepada kaumnya, mereka kembali dengan gembira ria (dan sombong). ', '', 'https://everyayah.com/data/Alafasy_128kbps/083031.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:32', 83, 32, 30, 588, 5880, 'وَاِذَا رَاَوْهُمْ قَالُوْٓا اِنَّ هٰٓؤُلَاۤءِ لَضَاۤلُّوْنَۙ', 'Apabila melihat (orang-orang mukmin), mereka mengatakan, “Sesungguhnya mereka benar-benar orang-orang sesat,”', '', 'https://everyayah.com/data/Alafasy_128kbps/083032.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:33', 83, 33, 30, 588, 5881, 'وَمَآ اُرْسِلُوْا عَلَيْهِمْ حٰفِظِيْنَۗ', 'padahal mereka (orang-orang yang berdosa itu) tidak diutus sebagai penjaga (orang-orang mukmin). ', '', 'https://everyayah.com/data/Alafasy_128kbps/083033.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:34', 83, 34, 30, 588, 5882, 'فَالْيَوْمَ الَّذِيْنَ اٰمَنُوْا مِنَ الْكُفَّارِ يَضْحَكُوْنَۙ', 'Pada hari ini (hari Kiamat), orang-orang yang berimanlah yang mentertawakan orang-orang kafir.', '', 'https://everyayah.com/data/Alafasy_128kbps/083034.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:35', 83, 35, 30, 589, 5883, 'عَلَى الْاَرَاۤىِٕكِ يَنْظُرُوْنَۗ', 'Mereka (duduk) di atas dipan-dipan (sambil) melepas pandangan.', '', 'https://everyayah.com/data/Alafasy_128kbps/083035.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('83:36', 83, 36, 30, 589, 5884, 'هَلْ ثُوِّبَ الْكُفَّارُ مَا كَانُوْا يَفْعَلُوْنَ ࣖ', 'Apakah orang-orang kafir itu telah diberi balasan (hukuman) terhadap apa yang selalu mereka perbuat?', '', 'https://everyayah.com/data/Alafasy_128kbps/083036.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('84:1', 84, 1, 30, 589, 5885, 'اِذَا السَّمَاۤءُ انْشَقَّتْۙ ', 'Apabila langit terbelah', '', 'https://everyayah.com/data/Alafasy_128kbps/084001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('84:2', 84, 2, 30, 589, 5886, 'وَاَذِنَتْ لِرَبِّهَا وَحُقَّتْۙ ', 'serta patuh kepada Tuhannya dan sudah semestinya patuh.', '', 'https://everyayah.com/data/Alafasy_128kbps/084002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('84:3', 84, 3, 30, 589, 5887, 'وَاِذَا الْاَرْضُ مُدَّتْۙ ', 'Apabila bumi diratakan,', '', 'https://everyayah.com/data/Alafasy_128kbps/084003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('84:4', 84, 4, 30, 589, 5888, 'وَاَلْقَتْ مَا فِيْهَا وَتَخَلَّتْۙ ', 'memuntahkan apa yang ada di dalamnya dan menjadi kosong,', '', 'https://everyayah.com/data/Alafasy_128kbps/084004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('84:5', 84, 5, 30, 589, 5889, 'وَاَذِنَتْ لِرَبِّهَا وَحُقَّتْۗ ', 'serta patuh kepada Tuhannya, dan sudah semestinya patuh.', '', 'https://everyayah.com/data/Alafasy_128kbps/084005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('84:6', 84, 6, 30, 589, 5890, 'يٰٓاَيُّهَا الْاِنْسَانُ اِنَّكَ كَادِحٌ اِلٰى رَبِّكَ كَدْحًا فَمُلٰقِيْهِۚ ', 'Wahai manusia, sesungguhnya engkau telah bekerja keras menuju (pertemuan dengan) Tuhanmu. Maka, engkau pasti menemui-Nya.751)', '751) Manusia di dunia ini, baik disadari maupun tidak, sedang dalam perjalanan menuju Tuhannya. Pasti dia akan bertemu dengan Tuhannya untuk menerima balasan atas perbuatannya yang buruk dan yang baik.', 'https://everyayah.com/data/Alafasy_128kbps/084006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('84:7', 84, 7, 30, 589, 5891, 'فَاَمَّا مَنْ اُوْتِيَ كِتٰبَهٗ بِيَمِيْنِهٖۙ ', 'Adapun orang yang catatannya diberikan dari sebelah kanannya, ', '', 'https://everyayah.com/data/Alafasy_128kbps/084007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('84:8', 84, 8, 30, 589, 5892, 'فَسَوْفَ يُحَاسَبُ حِسَابًا يَّسِيْرًاۙ ', 'dia akan dihisab dengan pemeriksaan yang mudah', '', 'https://everyayah.com/data/Alafasy_128kbps/084008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('84:9', 84, 9, 30, 589, 5893, 'وَّيَنْقَلِبُ اِلٰٓى اَهْلِهٖ مَسْرُوْرًاۗ ', 'dan dia akan kembali kepada keluarganya (yang sama-sama beriman) dengan gembira.', '', 'https://everyayah.com/data/Alafasy_128kbps/084009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('84:10', 84, 10, 30, 589, 5894, 'وَاَمَّا مَنْ اُوْتِيَ كِتٰبَهٗ وَرَاۤءَ ظَهْرِهٖۙ ', 'Adapun orang yang catatannya diberikan dari belakang punggungnya, ', '', 'https://everyayah.com/data/Alafasy_128kbps/084010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('84:11', 84, 11, 30, 589, 5895, 'فَسَوْفَ يَدْعُوْا ثُبُوْرًاۙ ', 'dia akan berteriak, “Celakalah aku!” ', '', 'https://everyayah.com/data/Alafasy_128kbps/084011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('84:12', 84, 12, 30, 589, 5896, 'وَّيَصْلٰى سَعِيْرًاۗ ', 'Dia akan memasuki (neraka) Sa‘ir (yang menyala-nyala).', '', 'https://everyayah.com/data/Alafasy_128kbps/084012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('84:13', 84, 13, 30, 589, 5897, 'اِنَّهٗ كَانَ فِيْٓ اَهْلِهٖ مَسْرُوْرًاۗ ', 'Sesungguhnya dia dahulu (di dunia) bergembira di kalangan keluarganya (yang sama-sama kafir). ', '', 'https://everyayah.com/data/Alafasy_128kbps/084013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('84:14', 84, 14, 30, 589, 5898, 'اِنَّهٗ ظَنَّ اَنْ لَّنْ يَّحُوْرَ ۛ ', 'Sesungguhnya dia mengira bahwa dia tidak akan kembali (kepada Tuhannya). ', '', 'https://everyayah.com/data/Alafasy_128kbps/084014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('84:15', 84, 15, 30, 589, 5899, 'بَلٰىۛ اِنَّ رَبَّهٗ كَانَ بِهٖ بَصِيْرًاۗ ', 'Tidak demikian. Sesungguhnya Tuhannya selalu melihatnya. ', '', 'https://everyayah.com/data/Alafasy_128kbps/084015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('84:16', 84, 16, 30, 589, 5900, 'فَلَآ اُقْسِمُ بِالشَّفَقِۙ ', 'Aku bersumpah demi cahaya merah pada waktu senja, ', '', 'https://everyayah.com/data/Alafasy_128kbps/084016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('84:17', 84, 17, 30, 589, 5901, 'وَالَّيْلِ وَمَا وَسَقَۙ ', 'demi malam dan apa yang diselubunginya,', '', 'https://everyayah.com/data/Alafasy_128kbps/084017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('84:18', 84, 18, 30, 589, 5902, 'وَالْقَمَرِ اِذَا اتَّسَقَۙ ', 'dan demi bulan apabila jadi purnama,', '', 'https://everyayah.com/data/Alafasy_128kbps/084018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('84:19', 84, 19, 30, 589, 5903, 'لَتَرْكَبُنَّ طَبَقًا عَنْ طَبَقٍۗ ', 'sungguh, kamu benar-benar akan menjalani tingkat demi tingkat (dalam kehidupan).752)', '752) Yang dimaksud dengan tingkat demi tingkat adalah perkembangan dari setetes mani menuju kelahiran, kanak-kanak, remaja, dewasa, dan tua atau perkembangan dari hidup menuju mati, kemudian dibangkitkan kembali.', 'https://everyayah.com/data/Alafasy_128kbps/084019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('84:20', 84, 20, 30, 589, 5904, 'فَمَا لَهُمْ لَا يُؤْمِنُوْنَۙ ', 'Maka, mengapa mereka tidak mau beriman?', '', 'https://everyayah.com/data/Alafasy_128kbps/084020.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('84:21', 84, 21, 30, 589, 5905, 'وَاِذَا قُرِئَ عَلَيْهِمُ الْقُرْاٰنُ لَا يَسْجُدُوْنَ ۗ ۩ ', 'Apabila Al-Qur’an dibacakan kepada mereka, mereka tidak (mau) bersujud,', '', 'https://everyayah.com/data/Alafasy_128kbps/084021.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('84:22', 84, 22, 30, 589, 5906, 'بَلِ الَّذِيْنَ كَفَرُوْا يُكَذِّبُوْنَۖ ', 'bahkan orang-orang yang kufur itu mendustakan(-nya).', '', 'https://everyayah.com/data/Alafasy_128kbps/084022.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('84:23', 84, 23, 30, 589, 5907, 'وَاللّٰهُ اَعْلَمُ بِمَا يُوْعُوْنَۖ ', 'Allah lebih mengetahui apa yang mereka sembunyikan (dalam hati mereka).', '', 'https://everyayah.com/data/Alafasy_128kbps/084023.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('84:24', 84, 24, 30, 589, 5908, 'فَبَشِّرْهُمْ بِعَذَابٍ اَلِيْمٍۙ ', 'Maka, berilah mereka kabar ‘gembira’ dengan azab yang pedih,', '', 'https://everyayah.com/data/Alafasy_128kbps/084024.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('84:25', 84, 25, 30, 589, 5909, 'اِلَّا الَّذِيْنَ اٰمَنُوْا وَعَمِلُوا الصّٰلِحٰتِ لَهُمْ اَجْرٌ غَيْرُ مَمْنُوْنٍ ࣖ ', 'Kecuali orang-orang yang beriman dan mengerjakan kebajikan. Bagi merekalah pahala yang tidak putus-putus.', '', 'https://everyayah.com/data/Alafasy_128kbps/084025.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('85:1', 85, 1, 30, 590, 5910, 'وَالسَّمَاۤءِ ذَاتِ الْبُرُوْجِۙ ', 'Demi langit yang mempunyai gugusan bintang,', '', 'https://everyayah.com/data/Alafasy_128kbps/085001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('85:2', 85, 2, 30, 590, 5911, 'وَالْيَوْمِ الْمَوْعُوْدِۙ ', 'demi hari yang dijanjikan,', '', 'https://everyayah.com/data/Alafasy_128kbps/085002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('85:3', 85, 3, 30, 590, 5912, 'وَشَاهِدٍ وَّمَشْهُوْدٍۗ ', 'demi yang menyaksikan dan yang disaksikan,', '', 'https://everyayah.com/data/Alafasy_128kbps/085003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('85:4', 85, 4, 30, 590, 5913, 'قُتِلَ اَصْحٰبُ الْاُخْدُوْدِۙ ', 'binasalah orang-orang yang membuat parit (tempat menyiksa orang mukmin)', '', 'https://everyayah.com/data/Alafasy_128kbps/085004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('85:5', 85, 5, 30, 590, 5914, 'النَّارِ ذَاتِ الْوَقُوْدِۙ ', '(yang dikobarkan) api penuh kayu bakar.', '', 'https://everyayah.com/data/Alafasy_128kbps/085005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('85:6', 85, 6, 30, 590, 5915, 'اِذْ هُمْ عَلَيْهَا قُعُوْدٌۙ ', 'Ketika (itu) mereka (hanya) duduk di sekitarnya. ', '', 'https://everyayah.com/data/Alafasy_128kbps/085006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('85:7', 85, 7, 30, 590, 5916, 'وَّهُمْ عَلٰى مَا يَفْعَلُوْنَ بِالْمُؤْمِنِيْنَ شُهُوْدٌ  ۗ ', 'Mereka menyaksikan apa yang mereka perbuat terhadap orang-orang mukmin.', '', 'https://everyayah.com/data/Alafasy_128kbps/085007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('85:8', 85, 8, 30, 590, 5917, 'وَمَا نَقَمُوْا مِنْهُمْ اِلَّآ اَنْ يُّؤْمِنُوْا بِاللّٰهِ الْعَزِيْزِ الْحَمِيْدِۙ ', 'Tidaklah mereka menyiksa (membakar) orang-orang mukmin itu, kecuali karena mereka beriman kepada Allah Yang Maha Perkasa lagi Maha Terpuji,', '', 'https://everyayah.com/data/Alafasy_128kbps/085008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('85:9', 85, 9, 30, 590, 5918, 'الَّذِيْ لَهٗ مُلْكُ السَّمٰوٰتِ وَالْاَرْضِ ۗوَاللّٰهُ عَلٰى كُلِّ شَيْءٍ شَهِيْدٌ  ۗ ', 'yang memiliki kerajaan langit dan bumi. Allah Maha Menyaksikan segala sesuatu.', '', 'https://everyayah.com/data/Alafasy_128kbps/085009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('85:10', 85, 10, 30, 590, 5919, 'اِنَّ الَّذِيْنَ فَتَنُوا الْمُؤْمِنِيْنَ وَالْمُؤْمِنٰتِ ثُمَّ لَمْ يَتُوْبُوْا فَلَهُمْ عَذَابُ جَهَنَّمَ وَلَهُمْ عَذَابُ الْحَرِيْقِۗ ', 'Sesungguhnya, orang-orang yang menimpakan cobaan (siksa) terhadap mukmin laki-laki dan perempuan, lalu mereka tidak bertobat, mereka akan mendapat azab Jahanam dan mereka akan mendapat azab (neraka) yang membakar.', '', 'https://everyayah.com/data/Alafasy_128kbps/085010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('85:11', 85, 11, 30, 590, 5920, 'اِنَّ الَّذِيْنَ اٰمَنُوْا وَعَمِلُوا الصّٰلِحٰتِ لَهُمْ جَنّٰتٌ تَجْرِيْ مِنْ تَحْتِهَا الْاَنْهٰرُ ەۗ ذٰلِكَ الْفَوْزُ الْكَبِيْرُۗ', 'Sesungguhnya, orang-orang yang beriman dan mengerjakan kebajikan, mereka akan mendapat surga yang mengalir di bawahnya sungai-sungai. Itulah kemenangan yang besar.', '', 'https://everyayah.com/data/Alafasy_128kbps/085011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('85:12', 85, 12, 30, 590, 5921, 'اِنَّ بَطْشَ رَبِّكَ لَشَدِيْدٌ ۗ ', 'Sesungguhnya azab Tuhanmu sangat keras.', '', 'https://everyayah.com/data/Alafasy_128kbps/085012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('85:13', 85, 13, 30, 590, 5922, 'اِنَّهٗ هُوَ يُبْدِئُ وَيُعِيْدُۚ ', 'Sesungguhnya Dialah yang memulai (penciptaan makhluk) dan yang mengembalikan (hidup setelah mati).', '', 'https://everyayah.com/data/Alafasy_128kbps/085013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('85:14', 85, 14, 30, 590, 5923, 'وَهُوَ الْغَفُوْرُ الْوَدُوْدُۙ ', 'Dialah Yang Maha Pengampun lagi Maha Pengasih,', '', 'https://everyayah.com/data/Alafasy_128kbps/085014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('85:15', 85, 15, 30, 590, 5924, 'ذُو الْعَرْشِ الْمَجِيْدُۙ ', 'Pemilik ʻArasy lagi Maha Mulia, ', '', 'https://everyayah.com/data/Alafasy_128kbps/085015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('85:16', 85, 16, 30, 590, 5925, 'فَعَّالٌ لِّمَا يُرِيْدُۗ ', 'Maha Kuasa berbuat apa saja yang Dia kehendaki.', '', 'https://everyayah.com/data/Alafasy_128kbps/085016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('85:17', 85, 17, 30, 590, 5926, 'هَلْ اَتٰىكَ حَدِيْثُ الْجُنُوْدِۙ ', 'Sudahkah sampai kepadamu berita tentang bala tentara,', '', 'https://everyayah.com/data/Alafasy_128kbps/085017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('85:18', 85, 18, 30, 590, 5927, 'فِرْعَوْنَ وَثَمُوْدَۗ ', '(yaitu bala tentara) Fir‘aun dan Samud?', '', 'https://everyayah.com/data/Alafasy_128kbps/085018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('85:19', 85, 19, 30, 590, 5928, 'بَلِ الَّذِيْنَ كَفَرُوْا فِيْ تَكْذِيْبٍۙ ', 'Memang orang-orang kafir (selalu) mendustakan,', '', 'https://everyayah.com/data/Alafasy_128kbps/085019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('85:20', 85, 20, 30, 590, 5929, 'وَّاللّٰهُ مِنْ وَّرَاۤىِٕهِمْ مُّحِيْطٌۚ ', 'padahal Allah mengepung dari belakang mereka.', '', 'https://everyayah.com/data/Alafasy_128kbps/085020.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('85:21', 85, 21, 30, 590, 5930, 'بَلْ هُوَ قُرْاٰنٌ مَّجِيْدٌۙ ', 'Bahkan, (yang didustakan itu) Al-Qur’an yang mulia', '', 'https://everyayah.com/data/Alafasy_128kbps/085021.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('85:22', 85, 22, 30, 590, 5931, 'فِيْ لَوْحٍ مَّحْفُوْظٍ ࣖ ', 'yang (tersimpan) dalam (tempat) yang terjaga (Lauhulmahfuz).', '', 'https://everyayah.com/data/Alafasy_128kbps/085022.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('86:1', 86, 1, 30, 591, 5932, 'وَالسَّمَاۤءِ وَالطَّارِقِۙ ', 'Demi langit dan yang datang pada malam hari.', '', 'https://everyayah.com/data/Alafasy_128kbps/086001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('86:2', 86, 2, 30, 591, 5933, 'وَمَآ اَدْرٰىكَ مَا الطَّارِقُۙ ', 'Tahukah kamu apakah yang datang pada malam hari itu?', '', 'https://everyayah.com/data/Alafasy_128kbps/086002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('86:3', 86, 3, 30, 591, 5934, 'النَّجْمُ الثَّاقِبُۙ ', '(Itulah) bintang yang bersinar tajam.', '', 'https://everyayah.com/data/Alafasy_128kbps/086003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('86:4', 86, 4, 30, 591, 5935, 'اِنْ كُلُّ نَفْسٍ لَّمَّا عَلَيْهَا حَافِظٌۗ ', 'Setiap orang pasti ada penjaganya.', '', 'https://everyayah.com/data/Alafasy_128kbps/086004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('86:5', 86, 5, 30, 591, 5936, 'فَلْيَنْظُرِ الْاِنْسَانُ مِمَّ خُلِقَ ', ' Hendaklah manusia memperhatikan dari apa dia diciptakan.', '', 'https://everyayah.com/data/Alafasy_128kbps/086005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('86:6', 86, 6, 30, 591, 5937, 'خُلِقَ مِنْ مَّاۤءٍ دَافِقٍۙ ', 'Dia diciptakan dari air (mani) yang memancar,', '', 'https://everyayah.com/data/Alafasy_128kbps/086006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('86:7', 86, 7, 30, 591, 5938, 'يَّخْرُجُ مِنْۢ بَيْنِ الصُّلْبِ وَالتَّرَاۤىِٕبِۗ ', 'yang keluar dari antara tulang sulbi (punggung) dan tulang dada.', '', 'https://everyayah.com/data/Alafasy_128kbps/086007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('86:8', 86, 8, 30, 591, 5939, 'اِنَّهٗ عَلٰى رَجْعِهٖ لَقَادِرٌۗ ', 'Sesungguhnya Dia (Allah) benar-benar kuasa untuk mengembalikannya (hidup setelah mati)', '', 'https://everyayah.com/data/Alafasy_128kbps/086008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('86:9', 86, 9, 30, 591, 5940, 'يَوْمَ تُبْلَى السَّرَاۤىِٕرُۙ ', 'pada hari ditampakkan segala rahasia.', '', 'https://everyayah.com/data/Alafasy_128kbps/086009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('86:10', 86, 10, 30, 591, 5941, 'فَمَا لَهٗ مِنْ قُوَّةٍ وَّلَا نَاصِرٍۗ ', 'Maka, baginya (manusia) tidak ada lagi kekuatan dan tidak (pula) ada penolong.', '', 'https://everyayah.com/data/Alafasy_128kbps/086010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('86:11', 86, 11, 30, 591, 5942, 'وَالسَّمَاۤءِ ذَاتِ الرَّجْعِۙ ', 'Demi langit yang mengandung hujan753)', '753) Raj‘ berarti ‘kembali berputar’. Hujan dinamakan raj‘ karena berasal dari uap yang naik dari bumi ke udara, kemudian turun ke bumi, kemudian menguap kembali ke atas, lalu turun kembali ke bumi, dan begituseterusnya.', 'https://everyayah.com/data/Alafasy_128kbps/086011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('86:12', 86, 12, 30, 591, 5943, 'وَالْاَرْضِ ذَاتِ الصَّدْعِۙ ', 'dan bumi yang memiliki rekahan (tempat tumbuhnya pepohonan),', '', 'https://everyayah.com/data/Alafasy_128kbps/086012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('86:13', 86, 13, 30, 591, 5944, 'اِنَّهٗ لَقَوْلٌ فَصْلٌۙ ', 'sesungguhnya (Al-Qur’an) itu benar-benar firman pemisah (antara yang hak dan yang batil)', '', 'https://everyayah.com/data/Alafasy_128kbps/086013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('86:14', 86, 14, 30, 591, 5945, 'وَّمَا هُوَ بِالْهَزْلِۗ ', 'dan ia (Al-Qur’an) sama sekali bukan perkataan senda gurau.', '', 'https://everyayah.com/data/Alafasy_128kbps/086014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('86:15', 86, 15, 30, 591, 5946, 'اِنَّهُمْ يَكِيْدُوْنَ كَيْدًاۙ ', 'Sesungguhnya mereka (orang kafir) melakukan tipu daya.', '', 'https://everyayah.com/data/Alafasy_128kbps/086015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('86:16', 86, 16, 30, 591, 5947, 'وَّاَكِيْدُ كَيْدًاۖ ', 'Aku pun membalasnya dengan tipu daya.', '', 'https://everyayah.com/data/Alafasy_128kbps/086016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('86:17', 86, 17, 30, 591, 5948, 'فَمَهِّلِ الْكٰفِرِيْنَ اَمْهِلْهُمْ رُوَيْدًا ࣖ ', 'Maka, tangguhkanlah orang-orang kafir itu. Biarkanlah mereka sejenak (bersenang-senang).', '', 'https://everyayah.com/data/Alafasy_128kbps/086017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('87:1', 87, 1, 30, 591, 5949, 'سَبِّحِ اسْمَ رَبِّكَ الْاَعْلَىۙ ', 'Sucikanlah nama Tuhanmu Yang Maha Tinggi,', '', 'https://everyayah.com/data/Alafasy_128kbps/087001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('87:2', 87, 2, 30, 591, 5950, 'الَّذِيْ خَلَقَ فَسَوّٰىۖ ', 'yang menciptakan, lalu menyempurnakan (ciptaan-Nya),', '', 'https://everyayah.com/data/Alafasy_128kbps/087002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('87:3', 87, 3, 30, 591, 5951, 'وَالَّذِيْ قَدَّرَ فَهَدٰىۖ ', 'yang menentukan kadar (masing-masing) dan memberi petunjuk,', '', 'https://everyayah.com/data/Alafasy_128kbps/087003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('87:4', 87, 4, 30, 591, 5952, 'وَالَّذِيْٓ اَخْرَجَ الْمَرْعٰىۖ ', 'dan yang menumbuhkan (rerumputan) padang gembala,', '', 'https://everyayah.com/data/Alafasy_128kbps/087004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('87:5', 87, 5, 30, 591, 5953, 'فَجَعَلَهٗ غُثَاۤءً اَحْوٰىۖ ', 'lalu menjadikannya kering kehitam-hitaman.', '', 'https://everyayah.com/data/Alafasy_128kbps/087005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('87:6', 87, 6, 30, 591, 5954, 'سَنُقْرِئُكَ فَلَا تَنْسٰىٓ  ۖ ', 'Kami akan membacakan (Al-Qur’an) kepadamu (Nabi Muhammad) sehingga engkau tidak akan lupa,', '', 'https://everyayah.com/data/Alafasy_128kbps/087006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('87:7', 87, 7, 30, 591, 5955, 'اِلَّا مَا شَاۤءَ اللّٰهُ ۗاِنَّهٗ يَعْلَمُ الْجَهْرَ وَمَا يَخْفٰىۗ ', 'kecuali jika Allah menghendaki. Sesungguhnya Dia mengetahui yang terang dan yang tersembunyi.', '', 'https://everyayah.com/data/Alafasy_128kbps/087007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('87:8', 87, 8, 30, 591, 5956, 'وَنُيَسِّرُكَ لِلْيُسْرٰىۖ ', 'Kami akan melapangkan bagimu jalan kemudahan (dalam segala urusan).', '', 'https://everyayah.com/data/Alafasy_128kbps/087008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('87:9', 87, 9, 30, 591, 5957, 'فَذَكِّرْ اِنْ نَّفَعَتِ الذِّكْرٰىۗ ', 'Maka, sampaikanlah peringatan jika peringatan itu bermanfaat.', '', 'https://everyayah.com/data/Alafasy_128kbps/087009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('87:10', 87, 10, 30, 591, 5958, 'سَيَذَّكَّرُ مَنْ يَّخْشٰىۙ ', 'Orang yang takut (kepada Allah) akan mengambil pelajaran,', '', 'https://everyayah.com/data/Alafasy_128kbps/087010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('87:11', 87, 11, 30, 591, 5959, 'وَيَتَجَنَّبُهَا الْاَشْقَىۙ ', 'sedangkan orang-orang yang celaka (kafir) akan menjauhinya,', '', 'https://everyayah.com/data/Alafasy_128kbps/087011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('87:12', 87, 12, 30, 591, 5960, 'الَّذِيْ يَصْلَى النَّارَ الْكُبْرٰىۚ ', '(yaitu) orang yang akan memasuki api (neraka) yang besar.', '', 'https://everyayah.com/data/Alafasy_128kbps/087012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('87:13', 87, 13, 30, 591, 5961, 'ثُمَّ لَا يَمُوْتُ فِيْهَا وَلَا يَحْيٰىۗ ', 'Selanjutnya, dia tidak mati dan tidak (pula) hidup di sana.', '', 'https://everyayah.com/data/Alafasy_128kbps/087013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('87:14', 87, 14, 30, 591, 5962, 'قَدْ اَفْلَحَ مَنْ تَزَكّٰىۙ ', 'Sungguh, beruntung orang yang menyucikan diri (dari kekafiran)', '', 'https://everyayah.com/data/Alafasy_128kbps/087014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('87:15', 87, 15, 30, 591, 5963, 'وَذَكَرَ اسْمَ رَبِّهٖ فَصَلّٰىۗ ', 'dan mengingat nama Tuhannya, lalu dia salat.', '', 'https://everyayah.com/data/Alafasy_128kbps/087015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('87:16', 87, 16, 30, 592, 5964, 'بَلْ تُؤْثِرُوْنَ الْحَيٰوةَ الدُّنْيَاۖ ', 'Adapun kamu (orang-orang kafir) mengutamakan kehidupan dunia,', '', 'https://everyayah.com/data/Alafasy_128kbps/087016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('87:17', 87, 17, 30, 592, 5965, 'وَالْاٰخِرَةُ خَيْرٌ وَّاَبْقٰىۗ ', 'padahal kehidupan akhirat itu lebih baik dan lebih kekal.', '', 'https://everyayah.com/data/Alafasy_128kbps/087017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('87:18', 87, 18, 30, 592, 5966, 'اِنَّ هٰذَا لَفِى الصُّحُفِ الْاُوْلٰىۙ ', 'Sesungguhnya (penjelasan) ini terdapat dalam suhuf (lembaran-lembaran) yang terdahulu,', '', 'https://everyayah.com/data/Alafasy_128kbps/087018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('87:19', 87, 19, 30, 592, 5967, 'صُحُفِ اِبْرٰهِيْمَ وَمُوْسٰى ࣖ ', '(yaitu) suhuf (yang diturunkan kepada) Ibrahim dan Musa.', '', 'https://everyayah.com/data/Alafasy_128kbps/087019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('88:1', 88, 1, 30, 592, 5968, 'هَلْ اَتٰىكَ حَدِيْثُ الْغَاشِيَةِۗ', 'Sudahkah sampai kepadamu berita tentang al-Gāsyiyah (hari Kiamat yang menutupi kesadaran manusia dengan kedahsyatannya)?', '', 'https://everyayah.com/data/Alafasy_128kbps/088001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('88:2', 88, 2, 30, 592, 5969, 'وُجُوْهٌ يَّوْمَىِٕذٍ خَاشِعَةٌ  ۙ', 'Pada hari itu banyak wajah yang tertunduk hina', '', 'https://everyayah.com/data/Alafasy_128kbps/088002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('88:3', 88, 3, 30, 592, 5970, 'عَامِلَةٌ نَّاصِبَةٌ  ۙ', '(karena) berusaha keras (menghindari azab neraka) lagi kepayahan (karena dibelenggu).', '', 'https://everyayah.com/data/Alafasy_128kbps/088003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('88:4', 88, 4, 30, 592, 5971, 'تَصْلٰى نَارًا حَامِيَةً  ۙ', 'Mereka memasuki api (neraka) yang sangat panas.', '', 'https://everyayah.com/data/Alafasy_128kbps/088004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('88:5', 88, 5, 30, 592, 5972, 'تُسْقٰى مِنْ عَيْنٍ اٰنِيَةٍ ۗ', '(Mereka) diberi minum dari sumber mata air yang sangat panas.', '', 'https://everyayah.com/data/Alafasy_128kbps/088005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('88:6', 88, 6, 30, 592, 5973, 'لَيْسَ لَهُمْ طَعَامٌ اِلَّا مِنْ ضَرِيْعٍۙ', 'Tidak ada makanan bagi mereka selain dari pohon yang berduri,', '', 'https://everyayah.com/data/Alafasy_128kbps/088006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('88:7', 88, 7, 30, 592, 5974, 'لَّا يُسْمِنُ وَلَا يُغْنِيْ مِنْ جُوْعٍۗ', 'yang tidak menggemukkan dan tidak pula menghilangkan lapar.', '', 'https://everyayah.com/data/Alafasy_128kbps/088007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('88:8', 88, 8, 30, 592, 5975, 'وُجُوْهٌ يَّوْمَىِٕذٍ نَّاعِمَةٌ  ۙ', 'Pada hari itu banyak (pula) wajah yang berseri-seri,', '', 'https://everyayah.com/data/Alafasy_128kbps/088008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('88:9', 88, 9, 30, 592, 5976, 'لِّسَعْيِهَا رَاضِيَةٌ  ۙ ', 'merasa puas karena usahanya.', '', 'https://everyayah.com/data/Alafasy_128kbps/088009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('88:10', 88, 10, 30, 592, 5977, 'فِيْ جَنَّةٍ عَالِيَةٍۙ', '(Mereka) dalam surga yang tinggi. ', '', 'https://everyayah.com/data/Alafasy_128kbps/088010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('88:11', 88, 11, 30, 592, 5978, 'لَّا تَسْمَعُ فِيْهَا لَاغِيَةً ۗ', 'Di sana kamu tidak mendengar (perkataan) yang tidak berguna.', '', 'https://everyayah.com/data/Alafasy_128kbps/088011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('88:12', 88, 12, 30, 592, 5979, 'فِيْهَا عَيْنٌ جَارِيَةٌ  ۘ', 'Di sana ada mata air yang mengalir.', '', 'https://everyayah.com/data/Alafasy_128kbps/088012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('88:13', 88, 13, 30, 592, 5980, 'فِيْهَا سُرُرٌ مَّرْفُوْعَةٌ  ۙ', 'Di sana ada (pula) dipan-dipan yang ditinggikan,', '', 'https://everyayah.com/data/Alafasy_128kbps/088013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('88:14', 88, 14, 30, 592, 5981, 'وَّاَكْوَابٌ مَّوْضُوْعَةٌ  ۙ', 'gelas-gelas yang tersedia (di dekatnya),', '', 'https://everyayah.com/data/Alafasy_128kbps/088014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('88:15', 88, 15, 30, 592, 5982, 'وَّنَمَارِقُ مَصْفُوْفَةٌ  ۙ ', 'bantal-bantal sandaran yang tersusun,', '', 'https://everyayah.com/data/Alafasy_128kbps/088015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('88:16', 88, 16, 30, 592, 5983, 'وَّزَرَابِيُّ مَبْثُوْثَةٌ  ۗ', 'dan permadani-permadani yang terhampar.', '', 'https://everyayah.com/data/Alafasy_128kbps/088016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('88:17', 88, 17, 30, 592, 5984, 'اَفَلَا يَنْظُرُوْنَ اِلَى الْاِبِلِ كَيْفَ خُلِقَتْۗ', 'Tidakkah mereka memperhatikan unta, bagaimana ia diciptakan?', '', 'https://everyayah.com/data/Alafasy_128kbps/088017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('88:18', 88, 18, 30, 592, 5985, 'وَاِلَى السَّمَاۤءِ كَيْفَ رُفِعَتْۗ', 'Bagaimana langit ditinggikan?', '', 'https://everyayah.com/data/Alafasy_128kbps/088018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('88:19', 88, 19, 30, 592, 5986, 'وَاِلَى الْجِبَالِ كَيْفَ نُصِبَتْۗ', 'Bagaimana gunung-gunung ditegakkan?', '', 'https://everyayah.com/data/Alafasy_128kbps/088019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('88:20', 88, 20, 30, 592, 5987, 'وَاِلَى الْاَرْضِ كَيْفَ سُطِحَتْۗ ', 'Bagaimana pula bumi dihamparkan?', '', 'https://everyayah.com/data/Alafasy_128kbps/088020.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('88:21', 88, 21, 30, 592, 5988, 'فَذَكِّرْۗ اِنَّمَآ اَنْتَ مُذَكِّرٌۙ', 'Maka, berilah peringatan karena sesungguhnya engkau (Nabi Muhammad) hanyalah pemberi peringatan.', '', 'https://everyayah.com/data/Alafasy_128kbps/088021.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('88:22', 88, 22, 30, 592, 5989, 'لَّسْتَ عَلَيْهِمْ بِمُصَيْطِرٍۙ', 'Engkau bukanlah orang yang berkuasa atas mereka.', '', 'https://everyayah.com/data/Alafasy_128kbps/088022.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('88:23', 88, 23, 30, 592, 5990, 'اِلَّا مَنْ تَوَلّٰى وَكَفَرَۙ', 'Akan tetapi, orang yang berpaling dan kufur,', '', 'https://everyayah.com/data/Alafasy_128kbps/088023.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('88:24', 88, 24, 30, 592, 5991, 'فَيُعَذِّبُهُ اللّٰهُ الْعَذَابَ الْاَكْبَرَۗ', 'Allah akan mengazabnya dengan azab yang paling besar.', '', 'https://everyayah.com/data/Alafasy_128kbps/088024.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('88:25', 88, 25, 30, 592, 5992, 'اِنَّ اِلَيْنَآ اِيَابَهُمْ', 'Sesungguhnya kepada Kamilah mereka kembali.', '', 'https://everyayah.com/data/Alafasy_128kbps/088025.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('88:26', 88, 26, 30, 592, 5993, 'ثُمَّ اِنَّ عَلَيْنَا حِسَابَهُمْ ࣖ', 'Kemudian, sesungguhnya Kamilah yang berhak melakukan hisab (perhitungan) atas mereka.', '', 'https://everyayah.com/data/Alafasy_128kbps/088026.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('89:1', 89, 1, 30, 593, 5994, 'وَالْفَجْرِۙ', 'Demi waktu fajar,', '', 'https://everyayah.com/data/Alafasy_128kbps/089001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('89:2', 89, 2, 30, 593, 5995, 'وَلَيَالٍ عَشْرٍۙ', 'demi malam yang sepuluh,754)', '754) Yang dimaksud dengan malam yang sepuluh adalah sepuluh malam terakhir bulan Ramadan. Ada pula yang mengatakan sepuluh pertama dari bulan Muharam, termasuk di dalamnya hari Asyura, dan ada pula yang mengatakan sepuluh malam pertama dari bulan Zulhijah.', 'https://everyayah.com/data/Alafasy_128kbps/089002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('89:3', 89, 3, 30, 593, 5996, 'وَّالشَّفْعِ وَالْوَتْرِۙ', 'demi yang genap dan yang ganjil,', '', 'https://everyayah.com/data/Alafasy_128kbps/089003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('89:4', 89, 4, 30, 593, 5997, 'وَالَّيْلِ اِذَا يَسْرِۚ', 'dan demi malam apabila berlalu.', '', 'https://everyayah.com/data/Alafasy_128kbps/089004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('89:5', 89, 5, 30, 593, 5998, 'هَلْ فِيْ ذٰلِكَ قَسَمٌ لِّذِيْ حِجْرٍۗ', 'Apakah pada yang demikian itu terdapat sumpah (yang dapat diterima) oleh (orang) yang berakal?', '', 'https://everyayah.com/data/Alafasy_128kbps/089005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('89:6', 89, 6, 30, 593, 5999, 'اَلَمْ تَرَ كَيْفَ فَعَلَ رَبُّكَ بِعَادٍۖ', 'Tidakkah engkau (Nabi Muhammad) memperhatikan bagaimana Tuhanmu berbuat terhadap (kaum) ‘Ad,', '', 'https://everyayah.com/data/Alafasy_128kbps/089006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('89:7', 89, 7, 30, 593, 6000, 'اِرَمَ ذَاتِ الْعِمَادِۖ', '(yaitu) penduduk Iram (ibu kota kaum ‘Ad) yang mempunyai bangunan-bangunan yang tinggi', '', 'https://everyayah.com/data/Alafasy_128kbps/089007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('89:8', 89, 8, 30, 593, 6001, 'الَّتِيْ لَمْ يُخْلَقْ مِثْلُهَا فِى الْبِلَادِۖ', 'yang sebelumnya tidak pernah dibangun (suatu kota pun) seperti itu di negeri-negeri (lain)?', '', 'https://everyayah.com/data/Alafasy_128kbps/089008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('89:9', 89, 9, 30, 593, 6002, 'وَثَمُوْدَ الَّذِيْنَ جَابُوا الصَّخْرَ بِالْوَادِۖ', '(Tidakkah engkau perhatikan pula kaum) Samud yang memotong batu-batu besar di lembah755)', '755) Lembah ini terletak di bagian utara Jazirah Arab, antara kota Madinah dan Syam. Mereka memotong-motong batu gunung untuk membangun gedung-gedung tempat tinggal dan ada pula yang melubangi gunung-gunung untuk tempat tinggal dan tempat berlindung.', 'https://everyayah.com/data/Alafasy_128kbps/089009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('89:10', 89, 10, 30, 593, 6003, 'وَفِرْعَوْنَ ذِى الْاَوْتَادِۖ', 'dan Fir‘aun yang mempunyai pasak-pasak (bangunan yang besar)', '', 'https://everyayah.com/data/Alafasy_128kbps/089010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('89:11', 89, 11, 30, 593, 6004, 'الَّذِيْنَ طَغَوْا فِى الْبِلَادِۖ', 'yang berbuat sewenang-wenang dalam negeri,', '', 'https://everyayah.com/data/Alafasy_128kbps/089011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('89:12', 89, 12, 30, 593, 6005, 'فَاَكْثَرُوْا فِيْهَا الْفَسَادَۖ', 'lalu banyak berbuat kerusakan di dalamnya (negeri itu),', '', 'https://everyayah.com/data/Alafasy_128kbps/089012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('89:13', 89, 13, 30, 593, 6006, 'فَصَبَّ عَلَيْهِمْ رَبُّكَ سَوْطَ عَذَابٍۖ', 'maka Tuhanmu menimpakan cemeti azab (yang dahsyat) kepada mereka?', '', 'https://everyayah.com/data/Alafasy_128kbps/089013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('89:14', 89, 14, 30, 593, 6007, 'اِنَّ رَبَّكَ لَبِالْمِرْصَادِۗ', 'Sesungguhnya Tuhanmu benar-benar mengawasi.', '', 'https://everyayah.com/data/Alafasy_128kbps/089014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('89:15', 89, 15, 30, 593, 6008, 'فَاَمَّا الْاِنْسَانُ اِذَا مَا ابْتَلٰىهُ رَبُّهٗ فَاَكْرَمَهٗ وَنَعَّمَهٗۙ فَيَقُوْلُ رَبِّيْٓ اَكْرَمَنِۗ', 'Adapun manusia, apabila Tuhan mengujinya lalu memuliakannya dan memberinya kenikmatan, berkatalah dia, “Tuhanku telah memuliakanku.”', '', 'https://everyayah.com/data/Alafasy_128kbps/089015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('89:16', 89, 16, 30, 593, 6009, 'وَاَمَّآ اِذَا مَا ابْتَلٰىهُ فَقَدَرَ عَلَيْهِ رِزْقَهٗ ەۙ فَيَقُوْلُ رَبِّيْٓ اَهَانَنِۚ', 'Sementara itu, apabila Dia mengujinya lalu membatasi rezekinya, berkatalah dia, “Tuhanku telah menghinaku.”756)', '756) Allah menyalahkan orang yang mengatakan bahwa kekayaan itu adalah suatu kemuliaan dan kemiskinan adalah suatu kehinaan, seperti yang tersebut pada ayat 15 dan 16. Sebenarnya, kekayaan dan kemiskinan adalah ujian Allah bagi hamba-hamba-Nya.', 'https://everyayah.com/data/Alafasy_128kbps/089016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('89:17', 89, 17, 30, 593, 6010, 'كَلَّا بَلْ لَّا تُكْرِمُوْنَ الْيَتِيْمَۙ', 'Sekali-kali tidak! Sebaliknya, kamu tidak memuliakan anak yatim,757)', '757) Maksudnya adalah tidak memberikan hak-hak anak yatim dan tidak berbuat baik kepadanya.', 'https://everyayah.com/data/Alafasy_128kbps/089017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('89:18', 89, 18, 30, 593, 6011, 'وَلَا تَحٰۤضُّوْنَ عَلٰى طَعَامِ الْمِسْكِيْنِۙ', 'tidak saling mengajak memberi makan orang miskin,', '', 'https://everyayah.com/data/Alafasy_128kbps/089018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('89:19', 89, 19, 30, 593, 6012, 'وَتَأْكُلُوْنَ التُّرَاثَ اَكْلًا لَّمًّاۙ', 'memakan harta warisan dengan cara mencampurbaurkan (yang halal dan yang haram),', '', 'https://everyayah.com/data/Alafasy_128kbps/089019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('89:20', 89, 20, 30, 593, 6013, 'وَّتُحِبُّوْنَ الْمَالَ حُبًّا جَمًّاۗ', 'dan mencintai harta dengan kecintaan yang berlebihan.', '', 'https://everyayah.com/data/Alafasy_128kbps/089020.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('89:21', 89, 21, 30, 593, 6014, 'كَلَّآ اِذَا دُكَّتِ الْاَرْضُ دَكًّا دَكًّاۙ', 'Jangan sekali-kali begitu! Apabila bumi diguncangkan berturut-turut (berbenturan),', '', 'https://everyayah.com/data/Alafasy_128kbps/089021.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('89:22', 89, 22, 30, 593, 6015, 'وَّجَاۤءَ رَبُّكَ وَالْمَلَكُ صَفًّا صَفًّاۚ', 'Tuhanmu datang, begitu pula para malaikat (yang datang) berbaris-baris,', '', 'https://everyayah.com/data/Alafasy_128kbps/089022.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('89:23', 89, 23, 30, 593, 6016, 'وَجِايْۤءَ يَوْمَىِٕذٍۢ بِجَهَنَّمَۙ يَوْمَىِٕذٍ يَّتَذَكَّرُ الْاِنْسَانُ وَاَنّٰى لَهُ الذِّكْرٰىۗ', 'dan pada hari itu (neraka) Jahanam didatangkan, sadarlah manusia pada hari itu juga. Akan tetapi, bagaimana bisa kesadaran itu bermanfaat baginya?', '', 'https://everyayah.com/data/Alafasy_128kbps/089023.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('89:24', 89, 24, 30, 594, 6017, 'يَقُوْلُ يٰلَيْتَنِيْ قَدَّمْتُ لِحَيَاتِيْۚ', 'Dia berkata, “Oh, seandainya dahulu aku mengerjakan (kebajikan) untuk hidupku ini!”', '', 'https://everyayah.com/data/Alafasy_128kbps/089024.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('89:25', 89, 25, 30, 594, 6018, 'فَيَوْمَىِٕذٍ لَّا يُعَذِّبُ عَذَابَهٗٓ اَحَدٌ ۙ', 'Pada hari itu tidak ada seorang pun yang mampu mengazab (seadil) azab-Nya.', '', 'https://everyayah.com/data/Alafasy_128kbps/089025.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('89:26', 89, 26, 30, 594, 6019, 'وَّلَا يُوْثِقُ وَثَاقَهٗٓ اَحَدٌ ۗ', 'Tidak ada seorang pun juga yang mampu mengikat (sekuat) ikatan-Nya.', '', 'https://everyayah.com/data/Alafasy_128kbps/089026.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('89:27', 89, 27, 30, 594, 6020, 'يٰٓاَيَّتُهَا النَّفْسُ الْمُطْمَىِٕنَّةُۙ', 'Wahai jiwa yang tenang,', '', 'https://everyayah.com/data/Alafasy_128kbps/089027.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('89:28', 89, 28, 30, 594, 6021, 'ارْجِعِيْٓ اِلٰى رَبِّكِ رَاضِيَةً مَّرْضِيَّةً ۚ', 'kembalilah kepada Tuhanmu dengan rida dan diridai.', '', 'https://everyayah.com/data/Alafasy_128kbps/089028.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('89:29', 89, 29, 30, 594, 6022, 'فَادْخُلِيْ فِيْ عِبٰدِيْۙ', 'Lalu, masuklah ke dalam golongan hamba-hamba-Ku', '', 'https://everyayah.com/data/Alafasy_128kbps/089029.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('89:30', 89, 30, 30, 594, 6023, 'وَادْخُلِيْ جَنَّتِيْ ࣖࣖ', 'dan masuklah ke dalam surga-Ku!', '', 'https://everyayah.com/data/Alafasy_128kbps/089030.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('90:1', 90, 1, 30, 594, 6024, 'لَآ اُقْسِمُ بِهٰذَا الْبَلَدِۙ', 'Aku bersumpah demi negeri ini (Makkah),', '', 'https://everyayah.com/data/Alafasy_128kbps/090001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('90:2', 90, 2, 30, 594, 6025, 'وَاَنْتَ حِلٌّۢ بِهٰذَا الْبَلَدِۙ', 'sedangkan engkau (Nabi Muhammad) bertempat tinggal di negeri (Makkah) ini.', '', 'https://everyayah.com/data/Alafasy_128kbps/090002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('90:3', 90, 3, 30, 594, 6026, 'وَوَالِدٍ وَّمَا وَلَدَۙ', '(Aku juga bersumpah) demi bapak dan anaknya,', '', 'https://everyayah.com/data/Alafasy_128kbps/090003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('90:4', 90, 4, 30, 594, 6027, 'لَقَدْ خَلَقْنَا الْاِنْسَانَ فِيْ كَبَدٍۗ', 'sungguh, Kami benar-benar telah menciptakan manusia dalam keadaan susah payah.', '', 'https://everyayah.com/data/Alafasy_128kbps/090004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('90:5', 90, 5, 30, 594, 6028, 'اَيَحْسَبُ اَنْ لَّنْ يَّقْدِرَ عَلَيْهِ اَحَدٌ ۘ', 'Apakah dia (manusia) itu mengira bahwa tidak ada seorang pun yang berkuasa atasnya?', '', 'https://everyayah.com/data/Alafasy_128kbps/090005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('90:6', 90, 6, 30, 594, 6029, 'يَقُوْلُ اَهْلَكْتُ مَالًا لُّبَدًاۗ', 'Dia mengatakan, “Aku telah menghabiskan harta yang banyak.”', '', 'https://everyayah.com/data/Alafasy_128kbps/090006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('90:7', 90, 7, 30, 594, 6030, 'اَيَحْسَبُ اَنْ لَّمْ يَرَهٗٓ اَحَدٌۗ', 'Apakah dia mengira bahwa tidak ada seorang pun yang melihatnya?', '', 'https://everyayah.com/data/Alafasy_128kbps/090007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('90:8', 90, 8, 30, 594, 6031, 'اَلَمْ نَجْعَلْ لَّهٗ عَيْنَيْنِۙ', 'Bukankah Kami telah menjadikan untuknya sepasang mata,', '', 'https://everyayah.com/data/Alafasy_128kbps/090008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('90:9', 90, 9, 30, 594, 6032, 'وَلِسَانًا وَّشَفَتَيْنِۙ', 'lidah, dan sepasang bibir,', '', 'https://everyayah.com/data/Alafasy_128kbps/090009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('90:10', 90, 10, 30, 594, 6033, 'وَهَدَيْنٰهُ النَّجْدَيْنِۙ', 'serta Kami juga telah menunjukkan kepadanya dua jalan (kebajikan dan kejahatan)?', '', 'https://everyayah.com/data/Alafasy_128kbps/090010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('90:11', 90, 11, 30, 594, 6034, 'فَلَا اقْتَحَمَ الْعَقَبَةَ ۖ', 'Maka, tidakkah sebaiknya dia menempuh jalan (kebajikan) yang mendaki dan sukar?', '', 'https://everyayah.com/data/Alafasy_128kbps/090011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('90:12', 90, 12, 30, 594, 6035, 'وَمَآ اَدْرٰىكَ مَا الْعَقَبَةُ ۗ', 'Tahukah kamu apakah jalan yang mendaki dan sukar itu?', '', 'https://everyayah.com/data/Alafasy_128kbps/090012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('90:13', 90, 13, 30, 594, 6036, 'فَكُّ رَقَبَةٍۙ', '(Itulah upaya) melepaskan perbudakan', '', 'https://everyayah.com/data/Alafasy_128kbps/090013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('90:14', 90, 14, 30, 594, 6037, 'اَوْ اِطْعَامٌ فِيْ يَوْمٍ ذِيْ مَسْغَبَةٍۙ', 'atau memberi makan pada hari terjadi kelaparan', '', 'https://everyayah.com/data/Alafasy_128kbps/090014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('90:15', 90, 15, 30, 594, 6038, 'يَّتِيْمًا ذَا مَقْرَبَةٍۙ', '(kepada) anak yatim yang memiliki hubungan kekerabatan', '', 'https://everyayah.com/data/Alafasy_128kbps/090015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('90:16', 90, 16, 30, 594, 6039, 'اَوْ مِسْكِيْنًا ذَا مَتْرَبَةٍۗ', 'atau orang miskin yang sangat membutuhkan.', '', 'https://everyayah.com/data/Alafasy_128kbps/090016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('90:17', 90, 17, 30, 594, 6040, 'ثُمَّ كَانَ مِنَ الَّذِيْنَ اٰمَنُوْا وَتَوَاصَوْا بِالصَّبْرِ وَتَوَاصَوْا بِالْمَرْحَمَةِۗ', 'Kemudian, dia juga termasuk orang-orang yang beriman dan saling berpesan untuk bersabar serta saling berpesan untuk berkasih sayang.', '', 'https://everyayah.com/data/Alafasy_128kbps/090017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('90:18', 90, 18, 30, 594, 6041, 'اُولٰۤىِٕكَ اَصْحٰبُ الْمَيْمَنَةِۗ', 'Mereka itulah golongan kanan. ', '', 'https://everyayah.com/data/Alafasy_128kbps/090018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('90:19', 90, 19, 30, 594, 6042, 'وَالَّذِيْنَ كَفَرُوْا بِاٰيٰتِنَا هُمْ اَصْحٰبُ الْمَشْـَٔمَةِۗ', 'Adapun orang-orang yang kufur pada ayat-ayat Kami, merekalah golongan kiri.', '', 'https://everyayah.com/data/Alafasy_128kbps/090019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('90:20', 90, 20, 30, 594, 6043, 'عَلَيْهِمْ نَارٌ مُّؤْصَدَةٌ ࣖ', 'Mereka berada dalam neraka yang ditutup rapat.', '', 'https://everyayah.com/data/Alafasy_128kbps/090020.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('91:1', 91, 1, 30, 595, 6044, 'وَالشَّمْسِ وَضُحٰىهَاۖ', 'Demi matahari dan sinarnya pada waktu duha (ketika matahari naik sepenggalah),', '', 'https://everyayah.com/data/Alafasy_128kbps/091001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('91:2', 91, 2, 30, 595, 6045, 'وَالْقَمَرِ اِذَا تَلٰىهَاۖ', 'demi bulan saat mengiringinya,', '', 'https://everyayah.com/data/Alafasy_128kbps/091002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('91:3', 91, 3, 30, 595, 6046, 'وَالنَّهَارِ اِذَا جَلّٰىهَاۖ', 'demi siang saat menampakkannya,', '', 'https://everyayah.com/data/Alafasy_128kbps/091003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('91:4', 91, 4, 30, 595, 6047, 'وَالَّيْلِ اِذَا يَغْشٰىهَاۖ', 'demi malam saat menutupinya (gelap gulita),', '', 'https://everyayah.com/data/Alafasy_128kbps/091004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('91:5', 91, 5, 30, 595, 6048, 'وَالسَّمَاۤءِ وَمَا بَنٰىهَاۖ', 'demi langit serta pembuatannya,', '', 'https://everyayah.com/data/Alafasy_128kbps/091005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('91:6', 91, 6, 30, 595, 6049, 'وَالْاَرْضِ وَمَا طَحٰىهَاۖ', ' demi bumi serta penghamparannya,', '', 'https://everyayah.com/data/Alafasy_128kbps/091006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('91:7', 91, 7, 30, 595, 6050, 'وَنَفْسٍ وَّمَا سَوّٰىهَاۖ', 'dan demi jiwa serta penyempurnaan (ciptaan)-nya,', '', 'https://everyayah.com/data/Alafasy_128kbps/091007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('91:8', 91, 8, 30, 595, 6051, 'فَاَلْهَمَهَا فُجُوْرَهَا وَتَقْوٰىهَاۖ', 'lalu Dia mengilhamkan kepadanya (jalan) kejahatan dan ketakwaannya,', '', 'https://everyayah.com/data/Alafasy_128kbps/091008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('91:9', 91, 9, 30, 595, 6052, 'قَدْ اَفْلَحَ مَنْ زَكّٰىهَاۖ', 'sungguh beruntung orang yang menyucikannya (jiwa itu)', '', 'https://everyayah.com/data/Alafasy_128kbps/091009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('91:10', 91, 10, 30, 595, 6053, 'وَقَدْ خَابَ مَنْ دَسّٰىهَاۗ', 'dan sungguh rugi orang yang mengotorinya.', '', 'https://everyayah.com/data/Alafasy_128kbps/091010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('91:11', 91, 11, 30, 595, 6054, 'كَذَّبَتْ ثَمُوْدُ بِطَغْوٰىهَآ  ۖ', '(Kaum) Samud telah mendustakan (rasulnya) karena mereka melampaui batas ', '', 'https://everyayah.com/data/Alafasy_128kbps/091011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('91:12', 91, 12, 30, 595, 6055, 'اِذِ انْۢبَعَثَ اَشْقٰىهَاۖ', 'ketika orang yang paling celaka di antara mereka bangkit (untuk menyembelih unta betina Allah).', '', 'https://everyayah.com/data/Alafasy_128kbps/091012.mp3');
